import{_ as o,o as r,c as a,a3 as l}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Git 分析器","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/git-analyzer.md","filePath":"user-guide/tools/git-analyzer.md","lastUpdated":1778221347000}'),e={name:"user-guide/tools/git-analyzer.md"};function n(i,t,d,s,g,h){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="git-分析器" tabindex="-1">Git 分析器 <a class="header-anchor" href="#git-分析器" aria-label="Permalink to &quot;Git 分析器&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>Git 分析器是一个直观的 Git 仓库提交历史分析工具。它帮你快速了解一个项目的开发节奏、贡献者分布和代码变更趋势——不需要背 Git 命令行参数，也不需要写脚本。选一个仓库，点一下&quot;加载&quot;，提交历史、统计数据和可视化图表一目了然。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>一键加载与分析</strong>：输入 Git 仓库路径，自动加载提交历史并计算统计数据（总提交数、贡献者数、时间跨度、日活跃度）</li><li><strong>多维筛选器</strong>：通过关键词、日期范围、作者、提交类型（feat/fix/docs 等）和范围滑块组合筛选，精准锁定目标提交</li><li><strong>提交详情与范围选择</strong>：通过滑块框定提交范围，支持标签快速定位（最新标签、两个标签间的区间），查看单条提交的完整信息和文件变更</li><li><strong>灵活导出</strong>：支持 Markdown、JSON、CSV、HTML 和纯文本五种格式，可精细控制导出内容（统计、提交、贡献者、时间线、图表数据等）</li><li><strong>统计图表可视化</strong>：直观的提交频率折线图、贡献者排行柱状图和热力图，一眼看出项目的开发活跃模式</li><li><strong>LLM 集成</strong>：分析结果可直接导出为格式化文本供 AI 聊天使用，或通过 Agent 接口由 LLM 直接查询仓库</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="首次使用-6-步走" tabindex="-1">首次使用 6 步走 <a class="header-anchor" href="#首次使用-6-步走" aria-label="Permalink to &quot;首次使用 6 步走&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在左侧工具列表中找到 <strong>Git 分析器</strong>，点击进入。你会看到一个简洁的信息卡片界面，顶部是工具栏和路径输入区。</p><blockquote><p>TODO: 截图 - 工具整体界面，标注路径输入框、加载按钮和主内容区</p></blockquote><p><strong>第二步：选择仓库路径</strong></p><p>有两种方式指定 Git 仓库：</p><ul><li><strong>手动输入</strong>：直接在路径输入框中键入或粘贴本地 Git 仓库的绝对路径例如 <code>D:\\projects\\my-app</code></li><li><strong>选择目录</strong>：点击路径框右侧的 <strong>选择</strong> 按钮，通过系统文件对话框选取仓库目录</li><li><strong>拖拽目录</strong>：将仓库文件夹从资源管理器拖拽到路径输入区域，松开即可自动填入路径</li></ul><p>路径支持自动补全，输入时会提示最近使用过的仓库路径。</p><blockquote><p>TODO: 截图 - 拖拽文件夹到路径输入框的效果</p></blockquote><p><strong>第三步：加载仓库</strong></p><p>路径输入好后，点击蓝色的 <strong>加载仓库</strong> 按钮。工具会自动：</p><ol><li>扫描仓库的分支列表</li><li>加载当前分支的提交历史</li><li>计算统计数据（总提交数、贡献者数等）</li></ol><p>加载过程中会显示进度条，如果仓库较大，你随时可以点击 <strong>终止加载</strong> 停止。提交记录默认显示最近 100 条，你可以调整数量。</p><blockquote><p>TODO: 截图 - 加载过程中的进度条显示</p></blockquote><p><strong>第四步：浏览提交列表</strong></p><p>加载完成后，主内容区会显示提交记录列表，每条记录包含：</p><ul><li>提交哈希（短格式，前 7 位）</li><li>作者名称和日期</li><li>提交消息摘要</li><li>代码变更统计（新增行数 + 删除行数 + 变更文件数）</li></ul><p>点击任意一条提交，会弹出详情对话框，展示完整的提交信息、文件变更列表和标签信息。</p><blockquote><p>TODO: 截图 - 提交列表视图，标注各信息字段</p></blockquote><p><strong>第五步：查看统计图表</strong></p><p>点击上方的 <strong>统计图表</strong> 标签页，切换到可视化视图。这里包含三个图表：</p><ul><li><strong>提交频率折线图</strong>：按日期展示每天的提交次数，直观反映开发活跃度</li><li><strong>贡献者排行柱状图</strong>：各贡献者的提交数量排行</li><li><strong>提交热力图</strong>：按星期几和小时维度展示提交分布模式</li></ul><p>图表会实时响应筛选条件的变化——当你调整筛选器后，图表会自动更新。</p><blockquote><p>TODO: 截图 - 统计图表视图，标注三个图表区域</p></blockquote><p><strong>第六步：导出分析结果</strong></p><p>点击工具栏的 <strong>导出</strong> 按钮，在弹出的对话框中配置导出选项。你可以选择：</p><ul><li><strong>导出格式</strong>：Markdown（默认）、JSON、CSV、HTML、纯文本</li><li><strong>包含内容</strong>：统计信息、提交记录、贡献者列表、时间线、图表数据</li><li><strong>提交范围</strong>：全部提交、当前筛选结果或自定义数量</li><li><strong>隐私选项</strong>：显示/隐藏作者名称和邮箱</li></ul><p>点击 <strong>导出</strong> 后，文件会保存到指定位置。</p><blockquote><p>TODO: 截图 - 导出对话框，标注各配置选项</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="控制面板" tabindex="-1">控制面板 <a class="header-anchor" href="#控制面板" aria-label="Permalink to &quot;控制面板&quot;">​</a></h3><p>控制面板位于界面上方，分为工具栏、筛选器、范围选择器和统计信息四个区域。</p><h4 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h4><p>工具栏固定在控制面板顶部，从左到右依次是：</p><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td><strong>路径输入框</strong></td><td>输入或粘贴 Git 仓库路径，支持拖拽</td></tr><tr><td><strong>选择按钮</strong></td><td>打开系统文件对话框选取目录</td></tr><tr><td><strong>分支选择器</strong></td><td>下拉选择要分析的分支，自动获取当前仓库的分支列表</td></tr><tr><td><strong>提交数量</strong></td><td>设置加载的提交记录数量（0 表示加载全部）</td></tr><tr><td><strong>批次大小</strong></td><td>流式加载时的每批数量（0 表示非流式加载）</td></tr><tr><td><strong>加载仓库</strong></td><td>开始加载提交历史；下拉菜单可选&quot;加载全部&quot;</td></tr></tbody></table><blockquote><p>TODO: 截图 - 工具栏全貌，标注各功能区域</p></blockquote><p><strong>分支选择</strong>：下拉分支列表时，需要加载分支列表，如果仓库较大可能会有短暂延迟。当前分支会标注 &quot;(当前)&quot; 字样。</p><p><strong>提交数量</strong>：默认 100 条。如果仓库提交非常多，建议从较小的数量开始加载，确认是自己需要的范围后再调到更大值。设置为 0 会加载仓库的所有提交记录。</p><p><strong>批次大小</strong>：流式加载模式下，每次批量处理多条记录，可以减少界面卡顿。默认为 20。设置为 0 会使用非流式加载（一次性全部加载），适合提交数较少的仓库。</p><h4 id="筛选器" tabindex="-1">筛选器 <a class="header-anchor" href="#筛选器" aria-label="Permalink to &quot;筛选器&quot;">​</a></h4><p>筛选器区域在工具栏下方，提供多种维度的筛选条件：</p><table tabindex="0"><thead><tr><th>筛选条件</th><th>说明</th></tr></thead><tbody><tr><td><strong>关键词搜索</strong></td><td>搜索提交哈希、提交消息或文件路径中包含的关键词</td></tr><tr><td><strong>排除关键词</strong></td><td>排除提交消息中包含特定关键词的提交</td></tr><tr><td><strong>日期范围</strong></td><td>选择起始和结束日期，只显示该时间段内的提交</td></tr><tr><td><strong>作者筛选</strong></td><td>按作者名称筛选（部分匹配）</td></tr><tr><td><strong>提交类型</strong></td><td>按 Conventional Commits 类型筛选（feat/fix/docs/style/refactor/perf/test/chore/build/ci/revert/other）</td></tr><tr><td><strong>倒序</strong></td><td>切换从最旧到最新的排列顺序</td></tr><tr><td><strong>清除</strong></td><td>一键清除所有筛选条件</td></tr></tbody></table><p>筛选器支持组合使用——同时设置关键词、日期范围和作者时，结果取交集。</p><blockquote><p>TODO: 截图 - 筛选器区域，标注所有筛选控件</p></blockquote><h4 id="提交范围滑块" tabindex="-1">提交范围滑块 <a class="header-anchor" href="#提交范围滑块" aria-label="Permalink to &quot;提交范围滑块&quot;">​</a></h4><p>在筛选器下方，有一个 <strong>提交范围</strong> 滑块，用于精确框定要操作的提交区间：</p><ul><li>滑块两端分别对应&quot;最新&quot;和&quot;最旧&quot;</li><li>拖动左右手柄调整范围</li><li>下方有精确的数字输入框，可以直接输入范围</li><li>右侧会显示当前范围内的提交数量</li></ul><p><strong>标签定位</strong>：滑块右侧有两个标签按钮：</p><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>定位到最新标签</strong></td><td>将范围设为从最新提交到最近的标签之间</td></tr><tr><td><strong>定位到标签区间</strong></td><td>将范围设为最近两个标签之间的提交区间</td></tr></tbody></table><p>这在查看版本发布之间的变更时非常有用——比如想知道 v1.0 到 v2.0 之间发生了哪些改动，点击 &quot;定位到标签区间&quot; 即可。</p><blockquote><p>TODO: 截图 - 提交范围滑块，标注手柄、数字输入框和标签定位按钮</p></blockquote><h4 id="统计信息" tabindex="-1">统计信息 <a class="header-anchor" href="#统计信息" aria-label="Permalink to &quot;统计信息&quot;">​</a></h4><p>当提交数据加载完成后，控制面板底部会显示四个统计指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td><strong>总提交数</strong></td><td>当前分支的总提交数量</td></tr><tr><td><strong>贡献者数</strong></td><td>提交历史中的独立作者数量</td></tr><tr><td><strong>时间跨度(天)</strong></td><td>从第一次提交到最后一次提交的天数</td></tr><tr><td><strong>平均提交/天</strong></td><td>总提交数 ÷ 时间跨度</td></tr></tbody></table><p>这些统计数字会随筛选条件变化而更新——当你应用筛选器后，统计值是筛选结果的统计。</p><blockquote><p>TODO: 截图 - 统计信息区域，标注四个指标</p></blockquote><h3 id="提交列表视图" tabindex="-1">提交列表视图 <a class="header-anchor" href="#提交列表视图" aria-label="Permalink to &quot;提交列表视图&quot;">​</a></h3><p>&quot;提交列表&quot;标签页是默认视图，以分页卡片列表展示每条提交记录。每条提交卡片包含：</p><ul><li><strong>序号</strong>：在列表中的位置编号</li><li><strong>提交哈希</strong>：短格式哈希，点击可复制完整哈希</li><li><strong>作者</strong>：提交者名称</li><li><strong>日期</strong>：提交时间（显示格式可在设置中调整）</li><li><strong>消息</strong>：提交消息摘要</li><li><strong>代码统计</strong>：新增行数（绿色）、删除行数（红色）、变更文件数（蓝色）</li></ul><blockquote><p>TODO: 截图 - 一条提交卡片的放大视图，标注各信息字段</p></blockquote><p><strong>分页</strong>：列表底部有分页器，默认每页 20 条，可在设置中调整。</p><p><strong>查看详情</strong>：点击任意提交卡片，会打开提交详情对话框，包含：</p><table tabindex="0"><thead><tr><th>信息</th><th>说明</th></tr></thead><tbody><tr><td><strong>完整哈希</strong></td><td>提交的完整 SHA 值，带复制按钮</td></tr><tr><td><strong>作者</strong></td><td>作者名称和邮箱</td></tr><tr><td><strong>日期</strong></td><td>提交时间</td></tr><tr><td><strong>提交消息</strong></td><td>提交消息全文</td></tr><tr><td><strong>标签</strong></td><td>该提交关联的标签</td></tr><tr><td><strong>分支</strong></td><td>该提交所属的分支</td></tr><tr><td><strong>文件变更</strong></td><td>变更文件列表（路径、变更类型、新增/删除行数）</td></tr><tr><td><strong>代码统计</strong></td><td>新增行、删除行、变更文件总数</td></tr></tbody></table><blockquote><p>TODO: 截图 - 提交详情对话框</p></blockquote><h3 id="统计图表视图" tabindex="-1">统计图表视图 <a class="header-anchor" href="#统计图表视图" aria-label="Permalink to &quot;统计图表视图&quot;">​</a></h3><p>&quot;统计图表&quot;标签页提供三个 ECharts 图表：</p><h4 id="提交频率折线图" tabindex="-1">提交频率折线图 <a class="header-anchor" href="#提交频率折线图" aria-label="Permalink to &quot;提交频率折线图&quot;">​</a></h4><p>按日期展示每天的提交次数。X 轴为日期，Y 轴为提交次数。你可以看到项目在哪几天特别活跃、哪些时间段比较平淡。</p><blockquote><p>TODO: 截图 - 提交频率折线图</p></blockquote><h4 id="贡献者排行柱状图" tabindex="-1">贡献者排行柱状图 <a class="header-anchor" href="#贡献者排行柱状图" aria-label="Permalink to &quot;贡献者排行柱状图&quot;">​</a></h4><p>各贡献者的提交数量排行。X 轴为贡献者名称，Y 轴为提交次数，按提交数降序排列。</p><blockquote><p>TODO: 截图 - 贡献者排行柱状图</p></blockquote><h4 id="提交热力图" tabindex="-1">提交热力图 <a class="header-anchor" href="#提交热力图" aria-label="Permalink to &quot;提交热力图&quot;">​</a></h4><p>按&quot;星期几 × 小时&quot;维度展示提交分布。X 轴为小时（0-23），Y 轴为星期（周一至周日），颜色深浅代表提交密度。这个图特别适合回答&quot;团队一般什么时候提交代码&quot;这类问题。</p><blockquote><p>TODO: 截图 - 提交热力图</p></blockquote><p>图表上方有 <strong>截图</strong> 按钮，方便你将图表保存为图片用于报告或演示。</p><h3 id="导出功能" tabindex="-1">导出功能 <a class="header-anchor" href="#导出功能" aria-label="Permalink to &quot;导出功能&quot;">​</a></h3><p>点击工具栏的 <strong>导出</strong> 按钮，打开导出配置对话框。</p><h4 id="导出格式" tabindex="-1">导出格式 <a class="header-anchor" href="#导出格式" aria-label="Permalink to &quot;导出格式&quot;">​</a></h4><table tabindex="0"><thead><tr><th>格式</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Markdown</strong></td><td>分享到文档、GitHub README 或知识库</td></tr><tr><td><strong>JSON</strong></td><td>程序化处理、数据迁移、与工具链集成</td></tr><tr><td><strong>CSV</strong></td><td>导入电子表格（Excel/Google Sheets）做进一步分析</td></tr><tr><td><strong>HTML</strong></td><td>生成可视化报告，支持浅色/深色主题自动适配</td></tr><tr><td><strong>纯文本</strong></td><td>快速粘贴到聊天、邮件等无格式场景</td></tr></tbody></table><h4 id="导出内容配置" tabindex="-1">导出内容配置 <a class="header-anchor" href="#导出内容配置" aria-label="Permalink to &quot;导出内容配置&quot;">​</a></h4><p>你可以精细控制导出包含哪些内容：</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td><strong>统计信息</strong></td><td>总提交数、贡献者数、时间跨度、平均日提交数</td></tr><tr><td><strong>提交记录</strong></td><td>提交详情列表</td></tr><tr><td><strong>贡献者列表</strong></td><td>贡献者名称和提交数（含占比）</td></tr><tr><td><strong>时间线</strong></td><td>每日提交数量的时间序列</td></tr><tr><td><strong>图表数据</strong></td><td>HTML 格式下包含统计图表的 base64 图片</td></tr></tbody></table><p><strong>提交范围</strong>：可选择&quot;全部提交&quot;、&quot;当前筛选结果&quot;或&quot;自定义数量&quot;。默认使用当前筛选结果。</p><p><strong>日期格式</strong>：支持 ISO 8601、本地时间、相对时间和 Unix 时间戳四种格式。</p><p><strong>隐私选项</strong>：可以控制在导出结果中是否显示作者名称和邮箱。邮箱默认隐藏。</p><p><strong>其他选项</strong>：完整提交消息、文件变更列表、标签信息、分支信息、代码统计等都可以独立开关。</p><blockquote><p>TODO: 截图 - 导出配置对话框的完整视图</p></blockquote><h4 id="html-导出特色" tabindex="-1">HTML 导出特色 <a class="header-anchor" href="#html-导出特色" aria-label="Permalink to &quot;HTML 导出特色&quot;">​</a></h4><p>选择 HTML 格式时，会生成一份完整的可视化报告，包含：</p><ul><li>仓库信息和分支信息头部</li><li>统计信息概览卡片</li><li>贡献者排行（含百分比进度条）</li><li>每日提交频率图表</li><li>提交记录列表（含文件变更详情）</li></ul><p>HTML 报告支持三种主题：<strong>跟随系统</strong>、<strong>浅色主题</strong>和<strong>深色主题</strong>，导出时选择即可。</p><blockquote><p>TODO: 截图 - HTML 导出的报告预览</p></blockquote><h3 id="配置自动保存" tabindex="-1">配置自动保存 <a class="header-anchor" href="#配置自动保存" aria-label="Permalink to &quot;配置自动保存&quot;">​</a></h3><p>Git 分析器会自动保存你的所有操作状态，包括仓库路径、选中的分支、筛选条件、导出配置等。下次打开工具时，所有状态都会自动恢复，无需重新配置。</p><blockquote><p>TODO: 截图 - 配置自动保存的示意</p></blockquote><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="与-ai-聊天联动" tabindex="-1">与 AI 聊天联动 <a class="header-anchor" href="#与-ai-聊天联动" aria-label="Permalink to &quot;与 AI 聊天联动&quot;">​</a></h3><p>分析结果可以通过多种方式与 AI 聊天联动：</p><p><strong>方式一：导出后发送</strong></p><p>将分析结果导出为 Markdown 或纯文本后，复制内容到 AI 聊天中，让 AI 帮你分析项目开发趋势。</p><p><strong>方式二：Agent 自然语言查询</strong></p><p>如果配置了 LLM 服务，可以直接在 AI 聊天中发起类似&quot;帮我分析 <code>D:\\projects\\my-app</code> 的提交历史&quot;或&quot;查看张三最近 50 条提交&quot;的请求，LLM 会自动调用 Git 分析器接口并返回格式化结果。</p><blockquote><p>TODO: 截图 - Agent 调用 Git 分析器的效果示意</p></blockquote><h3 id="版本发布分析的工作流" tabindex="-1">版本发布分析的工作流 <a class="header-anchor" href="#版本发布分析的工作流" aria-label="Permalink to &quot;版本发布分析的工作流&quot;">​</a></h3><p>通过提交范围滑块和标签定位功能，可以轻松分析版本发布之间的变更：</p><ol><li>加载仓库提交历史</li><li>点击 <strong>定位到标签区间</strong> 按钮，自动框定最近两个标签之间的范围</li><li>查看筛选后的结果和图表，了解该版本周期内的开发情况</li><li>导出为 Markdown 或 HTML 报告，作为发布说明的素材</li></ol><h3 id="团队协作分析" tabindex="-1">团队协作分析 <a class="header-anchor" href="#团队协作分析" aria-label="Permalink to &quot;团队协作分析&quot;">​</a></h3><p>利用作者筛选和贡献者排行，可以了解团队各成员的贡献情况：</p><ol><li>加载仓库后，在作者筛选框中输入某个成员的名字</li><li>统计信息会实时更新为该成员的提交统计</li><li>切换到图表视图查看该成员的提交时间分布</li><li>导出筛选结果作为绩效汇报的参考数据</li></ol><h3 id="大仓库的加载策略" tabindex="-1">大仓库的加载策略 <a class="header-anchor" href="#大仓库的加载策略" aria-label="Permalink to &quot;大仓库的加载策略&quot;">​</a></h3><p>对于有数万次提交的大型仓库，建议：</p><ol><li>先用默认的 100 条加载，确认分支选择和路径正确</li><li>逐步增加提交数量到需要的范围</li><li>使用批次大小控制流式加载速度，避免界面卡顿</li><li>利用关键词搜索快速定位感兴趣的提交，而不是盲目增加加载数量</li><li>使用日期范围筛选器缩小加载范围</li></ol><h3 id="项目活跃度监控" tabindex="-1">项目活跃度监控 <a class="header-anchor" href="#项目活跃度监控" aria-label="Permalink to &quot;项目活跃度监控&quot;">​</a></h3><p>定期使用 Git 分析器检查项目仓库：</p><ol><li>加载仓库后查看时间跨度和平均日提交数</li><li>切换到图表视图关注提交频率的趋势变化</li><li>查看贡献者排行了解新老成员的参与情况</li><li>导出 HTML 报告存档，方便后续对比</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么点击-加载仓库-后没有反应" tabindex="-1">Q：为什么点击&quot;加载仓库&quot;后没有反应？ <a class="header-anchor" href="#q-为什么点击-加载仓库-后没有反应" aria-label="Permalink to &quot;Q：为什么点击&quot;加载仓库&quot;后没有反应？&quot;">​</a></h3><p>有几种可能的原因：</p><ul><li><strong>路径不正确</strong>：请确认输入的路径是本地文件系统的绝对路径，而不是远程仓库地址（如 GitHub URL）</li><li><strong>不是 Git 仓库</strong>：该目录下可能缺少 <code>.git</code> 文件夹，可以通过命令行 <code>git status</code> 确认</li><li><strong>仓库被占用</strong>：其他 Git 操作（如正在 rebase 或 cherry-pick）可能导致仓库被锁定，等操作完成后再试</li><li><strong>权限不足</strong>：确认当前用户有读取该目录的权限</li></ul><blockquote><p>TODO: 截图 - 路径无效时的错误提示</p></blockquote><h3 id="q-加载大量提交时界面卡顿怎么办" tabindex="-1">Q：加载大量提交时界面卡顿怎么办？ <a class="header-anchor" href="#q-加载大量提交时界面卡顿怎么办" aria-label="Permalink to &quot;Q：加载大量提交时界面卡顿怎么办？&quot;">​</a></h3><p>可以尝试以下方法：</p><ul><li><strong>减少提交数量</strong>：先加载较少的提交（如 50 或 100 条），确认范围后再增加</li><li><strong>调整批次大小</strong>：较小的批次（如 10–20）可以减少单次处理的数据量，降低卡顿</li><li><strong>使用非流式加载</strong>：将批次大小设为 0，工具会一次性加载所有记录，适合提交数较少的仓库</li><li><strong>使用筛选器</strong>：先用日期范围或关键词缩小范围，再加载数据</li></ul><h3 id="q-为什么有些提交看不到文件变更" tabindex="-1">Q：为什么有些提交看不到文件变更？ <a class="header-anchor" href="#q-为什么有些提交看不到文件变更" aria-label="Permalink to &quot;Q：为什么有些提交看不到文件变更？&quot;">​</a></h3><p>提交的文件变更信息是通过 <code>git show --stat</code> 获取的。如果看不到文件变更，可能是因为：</p><ul><li><strong>加载时未获取详情</strong>：批量加载时默认只获取提交的摘要信息。查看详情时（点击提交卡片），会自动获取完整的文件变更列表</li><li><strong>Merge 提交</strong>：Merge 提交通常没有直接的代码变更，文件变更列表可能为空</li><li><strong>未跟踪变更</strong>：某些特殊操作（如 <code>git commit --allow-empty</code>）不会有任何文件变更</li></ul><h3 id="q-筛选器组合使用时结果为空" tabindex="-1">Q：筛选器组合使用时结果为空？ <a class="header-anchor" href="#q-筛选器组合使用时结果为空" aria-label="Permalink to &quot;Q：筛选器组合使用时结果为空？&quot;">​</a></h3><p>检查是否多个筛选条件互相冲突。例如：</p><ul><li>关键词搜索和排除关键词同时使用，可能导致所有提交都被排除</li><li>日期范围设置的太窄，没有覆盖任何提交的日期</li><li>提交类型和作者筛选组合，交集结果可能为空</li></ul><p>建议先单独使用每个筛选条件确认是否正常，然后再逐个组合排查问题。</p><h3 id="q-导出-html-报告很大怎么办" tabindex="-1">Q：导出 HTML 报告很大怎么办？ <a class="header-anchor" href="#q-导出-html-报告很大怎么办" aria-label="Permalink to &quot;Q：导出 HTML 报告很大怎么办？&quot;">​</a></h3><p>HTML 报告的大小主要受提交记录数量和图表数据影响。如果报告过大：</p><ul><li><strong>缩小提交范围</strong>：在导出对话框中选择&quot;当前筛选结果&quot;或缩小提交范围</li><li><strong>不包含图表数据</strong>：取消导出配置中的&quot;图表数据&quot;选项，减少 base64 图片的数据量</li><li><strong>减少包含内容</strong>：精简导出内容，如只选择统计信息和贡献者列表，不包含完整提交记录</li></ul>',140)])])}const q=o(e,[["render",n]]);export{u as __pageData,q as default};
